import{c as i,Q as a,j as l,m as o}from"./chunks/framework.DVkeSyfh.js";const h=JSON.parse('{"title":"Идеи","description":"","frontmatter":{},"headers":[],"relativePath":"ru/ideas.md","filePath":"ru/ideas.md","lastUpdated":1781921330000}'),d={name:"ru/ideas.md"};function t(r,e,s,c,u,p){return a(),l("div",null,[...e[0]||(e[0]=[o('<h1 id="идеи" tabindex="-1">Идеи <a class="header-anchor" href="#идеи" aria-label="Permalink to &quot;Идеи&quot;">​</a></h1><p>Эта страница хранит крупные идеи для будущих рабочих процессов, которые еще не реализованы. Ее нужно воспринимать как черновик продуктового направления: здесь описано, что можно попробовать сделать позже, но это не обещание текущего поведения, не стабильный API-контракт и не список уже готовых функций.</p><p>Пояснение: эта страница полезна как место для &quot;а что дальше?&quot;. Сюда можно складывать идеи, которые больше одного маленького улучшения UI, но еще не созрели до конкретного технического плана.</p><h2 id="smart-set-builder-по-seed-трекам" tabindex="-1">Smart Set Builder по seed-трекам <a class="header-anchor" href="#smart-set-builder-по-seed-трекам" aria-label="Permalink to &quot;Smart Set Builder по seed-трекам&quot;">​</a></h2><p>Идея: добавить отдельный UI-режим, который генерирует вариативный список кандидатов для DJ-сета на основе 3-10 выбранных seed-треков.</p><p>Seed-треки здесь означают несколько треков, которые пользователь вручную выбирает как отправную точку: например, &quot;вот такой грув&quot;, &quot;вот такая темнота&quot;, &quot;вот такой break&quot;, &quot;вот такая абстрактная фактура&quot;. Система должна не просто найти еще больше похожих треков, а выступить как куратор поверх уже накопленной аналитики библиотеки.</p><p>Цель такого режима:</p><ul><li>помочь быстро собрать кандидатов для прослушивания;</li><li>ускорить digging по большой локальной библиотеке;</li><li>предложить не только очевидные похожие треки, но и полезные соседние варианты;</li><li>подготовить последовательность, которую можно потом вручную проверить, отредактировать и экспортировать.</li></ul><p>Пояснение: обычный similarity search отвечает на вопрос &quot;что похоже на этот трек?&quot;. Smart Set Builder должен отвечать на более DJ-ориентированный вопрос: &quot;какой набор треков вокруг этих seed-треков может стать полезной подборкой или началом сета?&quot;.</p><h2 id="первая-версия-без-новои-модели" tabindex="-1">Первая версия без новой модели <a class="header-anchor" href="#первая-версия-без-новои-модели" aria-label="Permalink to &quot;Первая версия без новой модели&quot;">​</a></h2><p>Первую версию можно сделать без обучения отдельной новой модели. Вместо этого она может комбинировать уже существующие сигналы:</p><ul><li>MERT similarity для музыкальной и аудиальной близости. Это основной сигнал &quot;похоже по звучанию&quot;, особенно когда жанровые теги неполные или шумные.</li><li>MAEST labels для жанровых и текстурных подсказок. Это помогает понять, что трек относится к похожей музыкальной зоне, даже если MERT-сходство не идеально.</li><li>SONARA features для BPM, энергии и ритмической совместимости. Это важно именно для DJ-переходов: похожий по настроению трек может быть неудобен, если он слишком далеко по темпу или энергии.</li><li>promoted classifier scores, например <code>abstract_edge</code>, <code>break_energy</code> или <code>voice_presence</code>, как сигналы предпочтения и исключения. Такие классификаторы отражают личные пользовательские понятия, которые трудно выразить жанром.</li><li>исключение уже размеченных, лайкнутых, просмотренных или недавно показанных треков, когда пользователь хочет discovery, а не повторную проверку уже известных находок.</li></ul><p>Пояснение: это не один &quot;магический&quot; score. Скорее это агрегатор, который берет разные виды уже сохраненной информации и пытается собрать список, полезный для реальной музыкальной работы.</p><h2 id="возможные-режимы" tabindex="-1">Возможные режимы <a class="header-anchor" href="#возможные-режимы" aria-label="Permalink to &quot;Возможные режимы&quot;">​</a></h2><h3 id="similar-crate" tabindex="-1"><code>similar_crate</code> <a class="header-anchor" href="#similar-crate" aria-label="Permalink to &quot;`similar_crate`&quot;">​</a></h3><p>Режим близкой подборки. Он должен держаться рядом с seed-треками и ранжировать кандидатов по сильному совпадению сразу нескольких источников: MERT, MAEST, SONARA и promoted classifier scores.</p><p>Пояснение: это режим &quot;дай мне ящик похожего материала&quot;. Он нужен, когда seed уже точно попал в нужную зону, и задача не экспериментировать, а быстро найти еще треки рядом.</p><h3 id="weird-adjacent" tabindex="-1"><code>weird_adjacent</code> <a class="header-anchor" href="#weird-adjacent" aria-label="Permalink to &quot;`weird_adjacent`&quot;">​</a></h3><p>Режим странных, но релевантных соседей. Он должен сохранять достаточную похожесть на seed-треки, но предпочитать кандидатов с необычным расхождением моделей или более экспериментальной текстурой.</p><p>Пояснение: например, MERT говорит &quot;похоже&quot;, а MAEST или классификатор дают неожиданный сигнал. Такой трек может оказаться не очевидным клоном seed-трека, а интересным боковым ходом.</p><h3 id="balanced-set" tabindex="-1"><code>balanced_set</code> <a class="header-anchor" href="#balanced-set" aria-label="Permalink to &quot;`balanced_set`&quot;">​</a></h3><p>DJ-ориентированный режим. Он должен генерировать список с bridge-треками, совместимостью BPM/энергии и меньшим повторением слишком похожих треков подряд.</p><p>Пояснение: здесь важен не только выбор отдельных хороших кандидатов, но и порядок. Два трека могут быть отличными по отдельности, но плохо работать рядом из-за энергии, темпа или слишком похожей фактуры.</p><h3 id="discovery" tabindex="-1"><code>discovery</code> <a class="header-anchor" href="#discovery" aria-label="Permalink to &quot;`discovery`&quot;">​</a></h3><p>Режим поиска новых гипотез. Он может допускать более рискованных кандидатов и резервировать часть списка под low-confidence треки, которые потенциально помогут найти новые хорошие positives для пользовательских классификаторов.</p><p>Пояснение: это режим &quot;покажи мне то, в чем система не уверена, но что может оказаться полезным&quot;. Он особенно связан с active learning: пользователь слушает предложенные треки, отмечает удачные и тем самым улучшает будущие классификаторы.</p><h2 id="полезные-контролы-в-ui" tabindex="-1">Полезные контролы в UI <a class="header-anchor" href="#полезные-контролы-в-ui" aria-label="Permalink to &quot;Полезные контролы в UI&quot;">​</a></h2><p>В первом UI можно дать пользователю такие настройки:</p><ul><li>выбор seed-треков;</li><li>целевая длина списка;</li><li>уровень diversity, то есть насколько сильно список должен уходить от прямой похожести;</li><li>energy curve: <code>warmup</code>, <code>balanced</code>, <code>peak</code> или <code>wave</code>;</li><li>classifier targets и avoid rules;</li><li>исключение лайкнутых, размеченных, просмотренных или уже экспортированных треков;</li><li>опциональные ограничения по BPM/key compatibility.</li></ul><p>Пояснение по важным контролам:</p><ul><li><code>diversity</code> нужен, чтобы управлять балансом между &quot;все очень похоже&quot; и &quot;давай больше неожиданных вариантов&quot;.</li><li><code>energy_curve</code> нужна, чтобы список был похож не просто на выдачу поиска, а на возможную музыкальную траекторию.</li><li><code>classifier_targets</code> позволяют сказать &quot;хочу больше такого свойства&quot;, если оно уже выражено promoted classifier.</li><li><code>avoid rules</code> позволяют исключить нежелательные свойства, например слишком много вокала или слишком прямой грув, если для этого есть classifier score.</li></ul><h2 id="объяснимыи-результат" tabindex="-1">Объяснимый результат <a class="header-anchor" href="#объяснимыи-результат" aria-label="Permalink to &quot;Объяснимый результат&quot;">​</a></h2><p>Сгенерированный результат должен объяснять, почему каждый трек попал в список. Например:</p><ul><li><code>similar_to_seed</code>: трек близок к одному или нескольким seed-трекам.</li><li><code>bridge</code>: трек может связывать разные seed-зоны или соседние части списка.</li><li><code>weird_adjacent</code>: трек не очевидно похож, но находится рядом по важным признакам.</li><li><code>classifier_match</code>: трек выбран из-за сильного совпадения с promoted classifier.</li></ul><p>Также результат должен показывать базовые MERT/MAEST/SONARA/classifier scores для ручной проверки.</p><p>Пояснение: это важно, потому что пользователь не должен слепо доверять алгоритму. Если система показывает причины выбора и базовые scores, можно быстро понять, почему трек оказался в списке, оставить его, удалить или отправить на дальнейшую разметку.</p><h2 id="возможная-форма-api" tabindex="-1">Возможная форма API <a class="header-anchor" href="#возможная-форма-api" aria-label="Permalink to &quot;Возможная форма API&quot;">​</a></h2><p>Первый API может выглядеть так:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /api/set-builder/generate</span></span></code></pre></div><p>Поля входа:</p><ul><li><code>seed_track_ids</code>: список ID выбранных seed-треков.</li><li><code>limit</code>: сколько кандидатов вернуть.</li><li><code>mode</code>: режим генерации, например <code>similar_crate</code>, <code>weird_adjacent</code>, <code>balanced_set</code> или <code>discovery</code>.</li><li><code>diversity</code>: насколько сильно разрешено отходить от seed-треков.</li><li><code>energy_curve</code>: желаемая энергетическая траектория списка.</li><li><code>classifier_targets</code>: какие promoted classifier scores считать желательными.</li><li><code>exclude_reviewed</code>: исключать ли уже просмотренные кандидаты.</li></ul><p>Поля выхода:</p><ul><li>ранжированные track rows;</li><li>причина выбора для каждого трека;</li><li>similarity и diversity scores;</li><li>релевантные classifier scores;</li><li>опциональные данные порядка сета, например energy step или bridge target.</li></ul><p>Пояснение: API лучше держать генеративным, но проверяемым. Он не должен просто возвращать список ID. Ему стоит возвращать достаточно контекста, чтобы UI мог показать пользователю, как был собран результат.</p><h2 id="возможные-расширения-позже" tabindex="-1">Возможные расширения позже <a class="header-anchor" href="#возможные-расширения-позже" aria-label="Permalink to &quot;Возможные расширения позже&quot;">​</a></h2><p>После первой версии можно добавить:</p><ul><li>отправку выбранных треков в Rhythm Lab;</li><li>отметку кандидатов как reviewed;</li><li>экспорт M3U/XLSX списков;</li><li>сохранение сессий генерации;</li><li>итеративный active-learning workflow, где пользователь слушает кандидатов, размечает удачные и постепенно улучшает promoted classifiers.</li></ul><p>Пояснение: это превращает идею из одноразового генератора списков в рабочий цикл. Сначала система предлагает кандидатов, потом пользователь проверяет их, затем эти решения становятся данными для следующих classifier-профилей и будущих подборок.</p>',48)])])}const q=i(d,[["render",t]]);export{h as __pageData,q as default};
